// Determine which lead magnet template to use
const leadMagnet = $('Set: Structure Lead Data').item.json.leadMagnet;
const firstName = $('Set: Structure Lead Data').item.json.firstName;
const email = $('Set: Structure Lead Data').item.json.email;

// Email template based on lead magnet type
let subject = '';
let emailContent = '';

if (leadMagnet === 'paystub-generator') {
  subject = 'Your Free Paystub Generator - Plus Business Automation Tips';
  emailContent = `
    <div style="font-family: system-ui, -apple-system, sans-serif; max-width: 600px; margin: 0 auto;">
      <h2 style="color: #00D9FF;">Thanks for using our Paystub Generator!</h2>

      <p>Hi ${firstName || 'there'},</p>

      <p>I'm Richard Hudson, founder of Hudson Digital Solutions. Thanks for using our free paystub generator tool!</p>

      <p>I built this tool because I believe businesses should have access to simple, professional tools without the complexity or cost.</p>

      <h3>Quick question:</h3>
      <p><strong>Are you tired of repetitive tasks eating up your day?</strong></p>

      <p>If generating paystubs manually is one of your pain points, you might be surprised how much more we can automate:</p>

      <ul>
        <li>📧 <strong>Email workflows</strong> - Nurture leads while you sleep</li>
        <li>📊 <strong>Data entry automation</strong> - Stop copy-pasting between systems</li>
        <li>🤖 <strong>AI-powered lead qualification</strong> - Focus only on high-value prospects</li>
        <li>📄 <strong>Document generation</strong> - Proposals, invoices, reports in seconds</li>
        <li>🔗 <strong>System integrations</strong> - Connect your tools seamlessly</li>
      </ul>

      <p>We've helped businesses save 15-20 hours per week by automating workflows like these.</p>

      <h3>Want to see what's possible?</h3>

      <p>I offer a free 30-minute automation audit where we'll:</p>
      <ul>
        <li>Identify your biggest time-wasting tasks</li>
        <li>Show you exactly what can be automated</li>
        <li>Give you a custom roadmap (no obligation)</li>
      </ul>

      <p><a href="https://cal.com/hudsondigital" style="display: inline-block; background: #00D9FF; color: #000; padding: 12px 24px; text-decoration: none; border-radius: 6px; font-weight: bold; margin: 16px 0;">Book Your Free Automation Audit</a></p>

      <p>Not ready yet? No problem. Feel free to use our tools anytime.</p>

      <p>Best regards,<br>
      Richard Hudson<br>
      Founder, Hudson Digital Solutions<br>
      <a href="mailto:hello@hudsondigitalsolutions.com">hello@hudsondigitalsolutions.com</a></p>

      <p style="font-size: 0.9em; color: #6b7280; margin-top: 30px;">P.S. - We're a boutique consultancy, not an agency. You'll work directly with me, not a junior team member. Every automation is custom-built for your specific needs.</p>
    </div>
  `;
} else {
  // Generic lead magnet template
  subject = `Your ${leadMagnet} Resource - Hudson Digital Solutions`;
  emailContent = `
    <div style="font-family: system-ui, -apple-system, sans-serif; max-width: 600px; margin: 0 auto;">
      <h2 style="color: #00D9FF;">Thanks for downloading ${leadMagnet}!</h2>

      <p>Hi ${firstName || 'there'},</p>

      <p>I'm Richard Hudson, founder of Hudson Digital Solutions. Thanks for your interest in our resources!</p>

      <p>I'm here to help if you have any questions about implementing these strategies for your business.</p>

      <p><a href="https://cal.com/hudsondigital" style="display: inline-block; background: #00D9FF; color: #000; padding: 12px 24px; text-decoration: none; border-radius: 6px; font-weight: bold; margin: 16px 0;">Schedule a Free Consultation</a></p>

      <p>Best regards,<br>
      Richard Hudson<br>
      Founder, Hudson Digital Solutions<br>
      <a href="mailto:hello@hudsondigitalsolutions.com">hello@hudsondigitalsolutions.com</a></p>
    </div>
  `;
}

return {
  json: {
    email: email,
    firstName: firstName,
    leadMagnet: leadMagnet,
    subject: subject,
    emailContent: emailContent
  }
};

